$data_a = [
    "active" => [
        ["algo" => 1, "uuid" => "3e6fbf", "name" => "base16","type" => "encoding", "status" => "active","title" => "Base16 (Hex)","description_md" => "Base16 encodes binary data as hexadecimal characters (0-9, a-f). Every byte becomes two hex digits, making it 100% larger than raw binary. It is human-readable, easy to debug, and universally supported. Use it when you need to inspect raw bytes in logs, represent hashes, or embed binary in JSON/XML. It is slower and larger than Base64, so avoid for large payloads or wire transfer.","mental_model" => "Binary written in hexadecimal shorthand.","purpose" => ["represent binary as text", "debug raw bytes", "hash display"],"good_for" => ["hash strings", "debugging", "config files", "QR codes"],"avoid_for" => ["large file transfer", "bandwidth-sensitive APIs"],"pros" => ["human readable", "no padding issues", "easy to parse"],"cons" => ["2x size overhead", "slower than Base64"],"difficulty" => 1, "security" => 1,"quantum_impact" => "Not a cryptographic primitive; unaffected.","post_quantum_status" => 5,"example" => ["scenario" => "Displaying a SHA-256 hash","input" => ["binary" => "Hello, World!"],"output" => ["hex" => "48656c6c6f2c20576f726c6421"]],"flow" => ["take bytes", "map to hex chars", "concatenate"],"related" => ["base64", "base32", "hex"]],
        ["algo" => 2, "uuid" => "a6fdba", "name" => "base32","type" => "encoding", "status" => "active","title" => "Base32 (RFC 4648)","description_md" => "Base32 encodes binary into 32 ASCII characters (A-Z, 2-7). It is case-insensitive and avoids visually confusing characters, making it ideal for manual entry or voice transmission. Used in TOTP secrets, DNS TXT records, and legacy systems. It is 60% larger than binary and slower than Base64, but safer when humans must read or type the data.","mental_model" => "Binary spelled out in big letters and numbers.","purpose" => ["human-friendly encoding", "case-insensitive transfer", "manual entry"],"good_for" => ["2FA secrets", "DNS records", "license keys", "voice channels"],"avoid_for" => ["large payloads", "URL parameters"],"pros" => ["case-insensitive", "no special chars", "easy to type"],"cons" => ["60% overhead", "slower encoding", "padding required"],"difficulty" => 1, "security" => 1,"quantum_impact" => "Not a cryptographic primitive; unaffected.","post_quantum_status" => 5,"example" => ["scenario" => "TOTP secret for Google Authenticator","input" => ["binary" => "secret_key_123"],"output" => ["base32" => "ONSWG4TFOQ2HE2LOM4QWG3DJNZTS4===", "secret" => "JBSWY3DPEHPK3PXP"]],"flow" => ["group bits into 5s", "map to A-Z2-7", "pad with ="],"related" => ["base32hex", "base64", "bech32"]],
        ["algo" => 3, "uuid" => "7fe514", "name" => "base32hex","type" => "encoding", "status" => "active","title" => "Base32hex (RFC 4648)","description_md" => "Base32hex is a variant using 0-9, a-v instead of a-z, 2-7. It preserves sort order: encoded strings sort the same as the original binary. Useful in database indexing, file naming, and systems where lexicographic ordering matters. It is still case-insensitive but less human-friendly than standard Base32.","mental_model" => "Base32 that sorts like numbers.","purpose" => ["sortable encoding", "case-insensitive", "ordered storage"],"good_for" => ["database keys", "file naming", "sorted indexes", "logs"],"avoid_for" => ["human manual entry", "QR codes"],"pros" => ["preserves sort order", "case-insensitive", "standardized"],"cons" => ["less readable", "60% overhead", "not user-friendly"],"difficulty" => 1, "security" => 1,"quantum_impact" => "Not a cryptographic primitive; unaffected.","post_quantum_status" => 5,"example" => ["scenario" => "Sortable file IDs in object storage","input" => ["binary" => "\x01\x02\x03\x04"],"output" => ["base32hex" => "04h02d0c8"]],"flow" => ["group bits into 5s", "map to 0-9a-v", "pad if needed"],"related" => ["base32", "base64", "hex"]],
        ["algo" => 4, "uuid" => "10c74e", "name" => "base58","type" => "encoding", "status" => "active","title" => "Base58","description_md" => "Base58 removes 0, O, I, l, +, and / from Base64 to avoid visual ambiguity. It has no padding and produces compact strings. Originally created for Bitcoin addresses, it is now used in cryptocurrency wallets, IPFS hashes, and anywhere humans must read or transcribe identifiers. It is slower than Base64 due to big-number math.","mental_model" => "Base64 with confusing letters removed.","purpose" => ["human-readable IDs", "avoid ambiguity", "no padding"],"good_for" => ["crypto addresses", "wallet keys", "IPFS CIDs", "short URLs"],"avoid_for" => ["large data", "speed-critical paths"],"pros" => ["no visual ambiguity", "no padding", "compact"],"cons" => ["slower than Base64", "no checksum built-in", "not standardized"],"difficulty" => 2, "security" => 1,"quantum_impact" => "Not a cryptographic primitive; unaffected.","post_quantum_status" => 5,"example" => ["scenario" => "Bitcoin wallet address","input" => ["pubkey_hash" => "f54a5851e9372b87810a8e60cdd2e7cfd80b6e31"],"output" => ["address" => "1A1zP1eP5QGefi2DMPTfTL5SLmv7DivfNa"]],"flow" => ["treat as big integer", "divide by 58", "map to alphabet"],"related" => ["base58check", "base64", "bech32"]],
        ["algo" => 5, "uuid" => "557a4d", "name" => "base58check","type" => "encoding", "status" => "active","title" => "Base58Check","description_md" => "Base58Check adds a 4-byte checksum to Base58 to detect transcription errors. Used in Bitcoin WIF keys, extended keys (xpub/xprv), and legacy addresses. The checksum is double-SHA256 of the payload. If a user mistypes a character, the checksum fails and the error is caught immediately. It is the standard for cryptocurrency key representation.","mental_model" => "Base58 with a built-in typo detector.","purpose" => ["error detection", "human-readable keys", "prevent typos"],"good_for" => ["Bitcoin keys", "wallet exports", "paper backups", "crypto IDs"],"avoid_for" => ["non-crypto use", "when Bech32 is available"],"pros" => ["detects typos", "widely supported", "no ambiguity"],"cons" => ["longer than Base58", "legacy format", "slower validation"],"difficulty" => 2, "security" => 2,"quantum_impact" => "Checksum is not cryptographic; unaffected.","post_quantum_status" => 5,"example" => ["scenario" => "Bitcoin private key (WIF)","input" => ["privkey" => "e9873d79c6d87dc0fb6a5778633389f4453213303da61f20bd67fc233aa33262", "version" => "80"],"output" => ["wif" => "L4rK1yDtCWekvXuE6oXD9jCYfFNV2cWRpVuPLBcFWnA6f9xE1NXP"]],"flow" => ["add version byte", "double-SHA256", "append 4-byte checksum", "Base58 encode"],"related" => ["base58", "bech32", "sha256"]],
        ["algo" => 6, "uuid" => "e7373b", "name" => "base62","type" => "encoding", "status" => "active","title" => "Base62","description_md" => "Base62 uses 0-9, a-z, A-Z for a radix-62 representation. It is URL-safe, compact, and requires no padding. Common in URL shorteners, database IDs, and token generation. It is not standardized like Base64, so implementations vary in alphabet ordering. Good when you need short, readable strings without special characters.","mental_model" => "Numbers and letters only, no symbols.","purpose" => ["URL-safe encoding", "short strings", "no special chars"],"good_for" => ["short URLs", "invite codes", "session tokens", "DB IDs"],"avoid_for" => ["binary data", "checksums", "standardized systems"],"pros" => ["URL-safe", "no padding", "compact"],"cons" => ["not standardized", "case-sensitive", "slower than Base64"],"difficulty" => 1, "security" => 1,"quantum_impact" => "Not a cryptographic primitive; unaffected.","post_quantum_status" => 5,"example" => ["scenario" => "Short URL token","input" => ["id" => 123456789],"output" => ["token" => "8M0kX"]],"flow" => ["treat as big integer", "divide by 62", "map to 0-9a-zA-Z"],"related" => ["base64url", "base58", "hex"]],
        ["algo" => 7, "uuid" => "fdf3c3", "name" => "base64","type" => "encoding", "status" => "active","title" => "Base64 (RFC 4648)","description_md" => "Base64 is the standard binary-to-text encoding. It uses 64 ASCII characters plus padding '='. Every 3 bytes become 4 characters, adding 33% overhead. It is ubiquitous in email attachments, data URIs, JWT tokens, and JSON payloads. It is not encryption: anyone can decode it. Always use Base64url for URLs to avoid + and / issues.","mental_model" => "Binary dressed up as ASCII.","purpose" => ["binary in text", "data transfer", "storage"],"good_for" => ["JWT payloads", "email MIME", "data URIs", "JSON APIs"],"avoid_for" => ["URL parameters (use Base64url)", "secrets without encryption"],"pros" => ["universal support", "fast", "standardized"],"cons" => ["33% overhead", "not URL-safe", "not encryption"],"difficulty" => 1, "security" => 1,"quantum_impact" => "Not a cryptographic primitive; unaffected.","post_quantum_status" => 5,"example" => ["scenario" => "JWT header encoding","input" => ["json" => '{"alg":"HS256","typ":"JWT"}'],"output" => ["base64" => "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9"]],"flow" => ["group 3 bytes", "split into 6-bit chunks", "map to A-Za-z0-9+/", "pad with ="],"related" => ["base64url", "base32", "hex"]],
        ["algo" => 8, "uuid" => "d76057", "name" => "base64url","type" => "encoding", "status" => "active","title" => "Base64url (RFC 4648)","description_md" => "Base64url replaces + with - and / with _ and omits padding. It is URL-safe and filename-safe, making it the default for JWT, OAuth tokens, and modern APIs. It has the same 33% overhead as Base64 but avoids encoding issues in URLs and JSON. Always prefer this over standard Base64 for web applications.","mental_model" => "Base64 that plays nice with URLs.","purpose" => ["URL-safe encoding", "JWT tokens", "web APIs"],"good_for" => ["OAuth tokens", "JWT", "URL params", "cookies"],"avoid_for" => ["legacy systems expecting standard Base64", "email MIME"],"pros" => ["URL-safe", "no padding", "fast"],"cons" => ["33% overhead", "not human readable", "case-sensitive"],"difficulty" => 1, "security" => 1,"quantum_impact" => "Not a cryptographic primitive; unaffected.","post_quantum_status" => 5,"example" => ["scenario" => "OAuth2 access token payload","input" => ["json" => '{"sub":"user_42","scope":"read write"}'],"output" => ["base64url" => "eyJzdWIiOiJ1c2VyXzQyIiwic2NvcGUiOiJyZWFkIHdyaXRlIn0"]],"flow" => ["standard Base64", "replace +/ with -_", "strip padding"],"related" => ["base64", "base58", "jwt"]],
        ["algo" => 9, "uuid" => "1d5b39", "name" => "base85","type" => "encoding", "status" => "active","title" => "Base85 (Ascii85)","description_md" => "Base85 encodes 4 bytes into 5 ASCII characters, yielding only 25% overhead. It uses a larger character set including punctuation. Common in PostScript and PDF for embedding binary data in text streams. It is more compact than Base64 but requires careful handling of special characters in XML/HTML contexts. Not URL-safe.","mental_model" => "Base64 squeezed smaller with more symbols.","purpose" => ["compact encoding", "embed in documents", "PostScript/PDF"],"good_for" => ["PDF streams", "PostScript", "binary in XML", "data embedding"],"avoid_for" => ["URLs", "JSON", "user-facing strings"],"pros" => ["25% overhead (better than Base64)", "compact"],"cons" => ["special chars problematic", "not URL-safe", "less common"],"difficulty" => 2, "security" => 1,"quantum_impact" => "Not a cryptographic primitive; unaffected.","post_quantum_status" => 5,"example" => ["scenario" => "Embedding image in PDF","input" => ["binary" => "\x89PNG\r\n\x1a\n\x00\x00\x00\rIHDR"],"output" => ["base85" => "~>9jqo^BlbV-B5JBf[~>"]],"flow" => ["group 4 bytes", "treat as 32-bit int", "divide by 85", "map to ASCII 33-117"],"related" => ["base64", "base91", "hex"]],
        ["algo" => 11, "uuid" => "52f735", "name" => "bech32","type" => "encoding", "status" => "active","title" => "Bech32 (BIP-0173)","description_md" => "Bech32 is a checksummed encoding designed for Bitcoin SegWit addresses. It uses only lowercase letters and numbers, is case-insensitive, and includes a BCH error-correcting code that detects up to 4 errors. The human-readable part (HRP) identifies the chain. It is the modern replacement for Base58Check in Bitcoin and is adopted by Lightning Network.","mental_model" => "Crypto address with a built-in spell-checker.","purpose" => ["error-correcting addresses", "SegWit", "human-readable IDs"],"good_for" => ["Bitcoin SegWit", "Lightning invoices", "crypto addresses", "paper backups"],"avoid_for" => ["non-address data", "legacy Bitcoin P2PKH"],"pros" => ["error detection", "case-insensitive", "no ambiguity"],"cons" => ["longer than Base58", "Bitcoin-specific", "limited character set"],"difficulty" => 2, "security" => 3,"quantum_impact" => "Checksum not cryptographic; unaffected.","post_quantum_status" => 5,"example" => ["scenario" => "Bitcoin SegWit address","input" => ["witness_program" => "751e76e8199196d454941c45d1b3a323f1433bd6", "hrp" => "bc"],"output" => ["address" => "bc1qar0srrr7xfkvy5l643lydnw9re59gtzzwf5mdq"]],"flow" => ["add HRP", "convert to 5-bit groups", "append BCH checksum", "encode to lowercase"],"related" => ["bech32m", "base58check", "base32"]],
        ["algo" => 12, "uuid" => "743824", "name" => "bech32m","type" => "encoding", "status" => "active","title" => "Bech32m (BIP-0350)","description_md" => "Bech32m is an improved Bech32 with a stronger checksum (BCH code with different generator). It fixes a weakness where inserting/deleting characters could go undetected. Used for Bitcoin Taproot addresses (P2TR) and v1+ witness programs. It is backward-incompatible with Bech32 decoders, so wallets must explicitly support it.","mental_model" => "Bech32 with a tougher spell-checker.","purpose" => ["Taproot addresses", "improved error detection", "v1+ SegWit"],"good_for" => ["Bitcoin Taproot", "v1 witness", "future-proof addresses"],"avoid_for" => ["v0 SegWit (use Bech32)", "legacy wallets"],"pros" => ["stronger checksum", "insertion detection", "modern standard"],"cons" => ["not backward compatible", "longer addresses", "limited adoption"],"difficulty" => 2, "security" => 3,"quantum_impact" => "Checksum not cryptographic; unaffected.","post_quantum_status" => 5,"example" => ["scenario" => "Bitcoin Taproot address","input" => ["witness_program" => "a60869f0dbcf1dc659c9cecbaf8050135ea9e8cdc487053f1dc6880949dc684c", "hrp" => "bc"],"output" => ["address" => "bc1p5cyxnuxmeuwuvkwfem96lqzszd02n6xdcjrs20cac6yqjjwudpxqkedrcr"]],"flow" => ["add HRP", "convert to 5-bit groups", "append Bech32m checksum", "encode"],"related" => ["bech32", "base58check", "taproot"]],
        ["algo" => 13, "uuid" => "f05c9b", "name" => "pem","type" => "format", "status" => "active","title" => "PEM (Privacy Enhanced Mail)","description_md" => "PEM is the de-facto standard for encoding cryptographic keys and certificates as Base64 text between BEGIN/END headers. It is human-readable, copy-paste friendly, and supported by every TLS library. PEM can wrap X.509 certificates, RSA/EC private keys, CSRs, and more. The headers identify the content type. It is the format you see in .crt, .key, and .pem files.","mental_model" => "Certificate wrapped in ASCII armor.","purpose" => ["key storage", "certificate exchange", "config files"],"good_for" => ["TLS certs", "SSH keys", "API credentials", "backup"],"avoid_for" => ["in-band protocol data", "size-critical storage"],"pros" => ["human readable", "universal support", "self-describing"],"cons" => ["33% overhead", "parsing required", "no built-in encryption"],"difficulty" => 1, "security" => 2,"quantum_impact" => "Container format; quantum impact depends on enclosed algorithm.","post_quantum_status" => 3,"example" => ["scenario" => "TLS certificate file","input" => ["cert_data" => "X.509 DER bytes"],"output" => ["pem" => "-----BEGIN CERTIFICATE-----\nMIIDXTCCAkWgAwIBAgIJAJC1HiIAZAiUMA0GCSqGSIb3DQEBCwUAMEUxCzAJBgNV\n...\n-----END CERTIFICATE-----"]],"flow" => ["encode DER as Base64", "wrap in BEGIN/END headers", "add line breaks"],"related" => ["der", "pkcs7", "x509"]],
        ["algo" => 14, "uuid" => "d9840e", "name" => "der","type" => "format", "status" => "active","title" => "DER (Distinguished Encoding Rules)","description_md" => "DER is a strict binary encoding for ASN.1 data structures. It is the canonical format for X.509 certificates, PKCS keys, and CMS messages. Every element has a tag, length, and value. DER ensures identical byte-for-byte serialization, which is critical for digital signatures. It is not human-readable: use PEM for display and DER for storage/transmission.","mental_model" => "Strict binary blueprint for structured data.","purpose" => ["canonical encoding", "signatures", "certificates"],"good_for" => ["X.509 certs", "PKCS structures", "signed data", "TLS handshakes"],"avoid_for" => ["human editing", "debugging", "config files"],"pros" => ["canonical (bit-exact)", "compact", "standardized"],"cons" => ["not human readable", "rigid structure", "complex parsing"],"difficulty" => 3, "security" => 2,"quantum_impact" => "Container format; quantum impact depends on enclosed algorithm.","post_quantum_status" => 3,"example" => ["scenario" => "Raw certificate bytes","input" => ["asn1_structure" => "SEQUENCE of certificate fields"],"output" => ["der" => "308201a73082014f020101300d06092a864886f70d01010b0500..."]],"flow" => ["encode ASN.1", "tag-length-value", "canonical ordering", "no optional whitespace"],"related" => ["pem", "ber", "asn1"]],
        ["algo" => 16, "uuid" => "9d557e", "name" => "cer","type" => "format", "status" => "active","title" => "CER (Canonical Encoding Rules)","description_md" => "CER is a variant of DER with relaxed length constraints, allowing indefinite-length encoding for very large structures. It is rarely used in practice: most systems prefer DER for its strictness. CER is specified for environments where data size is unknown during encoding. In modern TLS and PKI, DER dominates. CER files are often just DER certificates with a different extension.","mental_model" => "DER with a flexible size option.","purpose" => ["large structure encoding", "streaming", "legacy systems"],"good_for" => ["very large certificates", "streaming ASN.1", "legacy PKI"],"avoid_for" => ["modern TLS", "signatures", "strict parsing"],"pros" => ["handles large data", "streaming friendly"],"cons" => ["rarely used", "less strict", "confusing vs DER"],"difficulty" => 3, "security" => 2,"quantum_impact" => "Container format; quantum impact depends on enclosed algorithm.","post_quantum_status" => 3,"example" => ["scenario" => "Large attribute certificate","input" => ["asn1_data" => "indefinite length structure"],"output" => ["cer" => "3080...0000 (indefinite length encoding)"]],"flow" => ["encode ASN.1", "allow indefinite length", "streaming chunks"],"related" => ["der", "ber", "pem"]],
        ["algo" => 17, "uuid" => "9311b8", "name" => "pkcs7","type" => "format", "status" => "active","title" => "PKCS#7 / CMS","description_md" => "PKCS#7 (now CMS) is the standard for signed and encrypted envelopes. It packages data with signatures, certificates, and recipient info. Used in S/MIME email, code signing, and document security. A PKCS#7 file (.p7b, .p7s) can contain a certificate chain without the private key. It is the backbone of secure email and software distribution.","mental_model" => "Sealed envelope with signatures and certificates inside.","purpose" => ["signed envelopes", "encrypted mail", "certificate chains"],"good_for" => ["S/MIME", "code signing", "document signing", "cert chains"],"avoid_for" => ["simple key storage", "modern JSON APIs", "lightweight apps"],"pros" => ["standardized", "supports chains", "widely supported"],"cons" => ["complex", "legacy ASN.1", "bloated"],"difficulty" => 4, "security" => 3,"quantum_impact" => "Depends on enclosed algorithms; RSA/ECDSA vulnerable.","post_quantum_status" => 2,"example" => ["scenario" => "S/MIME signed email","input" => ["email_body" => "Hello, this is signed.", "signer_cert" => "X.509 cert"],"output" => ["p7s" => "-----BEGIN PKCS7-----\nMIAGCSqGSIb3DQEHAqCAMIACAQExADALBgkqhkiG9w0BBwGggDCC...\n-----END PKCS7-----"]],"flow" => ["hash content", "sign hash", "wrap in CMS structure", "add certs"],"related" => ["pkcs12", "smime", "cms", "x509"]],
        ["algo" => 18, "uuid" => "a0ea5d", "name" => "pkcs8","type" => "format", "status" => "active","title" => "PKCS#8","description_md" => "PKCS#8 is the standard format for private keys, independent of algorithm. It wraps the algorithm identifier with the key material. It can be unencrypted (for automation) or encrypted with PBKDF2 (for storage). It is the modern alternative to PKCS#1 (RSA-only) and is used for RSA, EC, and Ed25519 keys. OpenSSL and Java use it internally.","mental_model" => "Universal private key container.","purpose" => ["private key storage", "algorithm-agnostic", "encrypted keys"],"good_for" => ["RSA keys", "EC keys", "Ed25519", "key databases"],"avoid_for" => ["public keys", "certificates", "simple configs"],"pros" => ["algorithm agnostic", "supports encryption", "standardized"],"cons" => ["complex", "requires parsing", "legacy baggage"],"difficulty" => 3, "security" => 3,"quantum_impact" => "Depends on key algorithm; RSA/EC vulnerable.","post_quantum_status" => 2,"example" => ["scenario" => "Encrypted Ed25519 private key","input" => ["privkey" => "ed25519_seed", "password" => "hunter2"],"output" => ["pkcs8" => "-----BEGIN ENCRYPTED PRIVATE KEY-----\nMIIFLTBXBgkqhkiG9w0BBQ0wSjApBgkqhkiG9w0BBQwwHAQIc7...\n-----END ENCRYPTED PRIVATE KEY-----"]],"flow" => ["wrap key in PKCS8 structure", "add algorithm ID", "encrypt if needed"],"related" => ["pkcs1", "pkcs12", "pem", "der"]],
        ["algo" => 19, "uuid" => "fdfdec", "name" => "pkcs12","type" => "format", "status" => "active","title" => "PKCS#12 (PFX)","description_md" => "PKCS#12 bundles a private key with its certificate chain into a single encrypted file (.pfx, .p12). It uses PBKDF2 and weak ciphers (3DES, RC2) by default for backward compatibility. Common for TLS certificate deployment, client auth, and backup. Modern use should specify strong encryption (AES-256) during export. It is the Swiss Army knife of certificate portability.","mental_model" => "Key and certificate chain in a password-protected zip.","purpose" => ["key+cert bundle", "backup", "client auth"],"good_for" => ["TLS deployment", "client certificates", "key backup", "Java keystore import"],"avoid_for" => ["public distribution", "modern APIs", "when PEM works"],"pros" => ["single file", "password protected", "includes chain"],"cons" => ["legacy ciphers by default", "complex", "proprietary feel"],"difficulty" => 3, "security" => 2,"quantum_impact" => "Depends on enclosed algorithms; default ciphers weak.","post_quantum_status" => 2,"example" => ["scenario" => "TLS certificate bundle for nginx","input" => ["cert" => "server.crt", "key" => "server.key", "ca" => "ca.crt", "password" => "SecureP@ss123"],"output" => ["p12" => "server.p12 (binary bundle)"]],"flow" => ["combine cert+key+chain", "encrypt with PBKDF2", "DER encode", "wrap in PKCS12"],"related" => ["pkcs7", "pem", "jks", "tls"]],
        ["algo" => 20, "uuid" => "88e9ca", "name" => "spki","type" => "format", "status" => "active","title" => "SPKI (SubjectPublicKeyInfo)","description_md" => "SPKI is the ASN.1 structure for public keys, defined in RFC 5280. It contains an algorithm identifier and the raw key bits. It is the standard way to represent public keys in X.509 certificates and TLS handshakes. SPKI can wrap RSA, EC, Ed25519, and Dilithium keys. The fingerprint of an SPKI is often used for certificate pinning.","mental_model" => "Public key with a name tag.","purpose" => ["public key representation", "certificates", "pinning"],"good_for" => ["TLS", "certificate pinning", "key exchange", "SSH"],"avoid_for" => ["private keys", "small payloads", "non-crypto use"],"pros" => ["algorithm agnostic", "standardized", "compact"],"cons" => ["ASN.1 complexity", "not human readable", "requires parsing"],"difficulty" => 3, "security" => 2,"quantum_impact" => "Depends on key algorithm; RSA/EC vulnerable.","post_quantum_status" => 2,"example" => ["scenario" => "RSA public key in certificate","input" => ["modulus" => "00c7...f3", "exponent" => "010001"],"output" => ["spki" => "30820122300d06092a864886f70d01010105000382010f003082010a0282010100c7..."]],"flow" => ["algorithm identifier", "bit string wrapping", "DER encoding"],"related" => ["pkcs8", "x509", "pem", "der"]],
        ["algo" => 21, "uuid" => "d9c441", "name" => "ff70","type" => "encoding", "status" => "active","title" => "FF70 (FlexFrame70)","description_md" => "FF70 or FlexFrame70 is QudsLab's custom framed Base-N encoding system designed for transporting and displaying binary data in a human-readable but configurable format. Unlike fixed encodings such as Base64 or Base58, FF70 can dynamically exclude problematic characters depending on the target environment while still preserving a self-describing structure.\n\nThe format combines:\n- configurable alphabets\n- binary-to-text conversion\n- checksum verification\n- lightweight metadata framing\n\nFF70 is intended for challenge tokens, binary blobs, key exchange displays, transport-safe identifiers, debugging output, and environments where certain characters may break rendering, transport, parsing, or legacy systems.\n\nThe encoding is not an industry standard and should mainly be used inside QudsLab tooling or systems that explicitly support the FF70 framing format.","mental_model" => "Base58 mixed with a lightweight transport container.","purpose" => ["human-readable binary transport", "safe challenge/token display", "transport-safe identifiers", "custom protocol framing", "environment-specific character compatibility"],"good_for" => ["CLI tools", "QR-safe payloads", "challenge-response systems", "copy-paste friendly tokens", "restricted character environments", "custom binary transport"],"avoid_for" => ["public interoperability", "RFC-standard protocols", "long-term archival formats", "browser-native encoding", "cryptographic authentication"],"pros" => ["human-readable structure", "dynamic alphabet support", "integrated checksum", "preserves leading zero bytes", "self-describing format", "flexible for hostile text environments"],"cons" => ["not standardized", "no canonical representation", "dynamic alphabets complicate interoperability", "4-byte checksum is not secure authentication", "larger output than Base64", "custom parser required"],"difficulty" => 6, "security" => 2,"quantum_impact" => "Not a cryptographic primitive; unaffected by quantum computing.","post_quantum_status" => 5,"example" => ["scenario" => "Transporting binary challenge data safely through a restricted text system","input" => ["binary_hex" => "deadbeefcafebabe", "header" => "auth", "exclude_chars" => "O0Il+/", "meta" => "nodeA"],"output" => ["ff70" => "[auth](-O0Il+/){7nZxQ4fG#v|1x9A}[nodeA]"]],"flow" => ["build alphabet from FF70 super-set", "remove excluded characters", "hash payload using BLAKE3", "truncate checksum to 4 bytes", "encode payload using Base-N bigint conversion", "encode checksum using same alphabet", "wrap result using FF70 framing format"],"related" => ["base58", "base62", "base64", "bech32", "multibase", "blake3"]],
        ["algo" => 22, "uuid" => "e86fa9", "name" => "crc8","type" => "checksum", "status" => "active","title" => "CRC-8","description_md" => "CRC-8 is a 1-byte cyclic redundancy check for detecting accidental errors in small payloads. Common in SMBus, 1-Wire, and CAN bus protocols. It catches all single-bit errors and most multi-bit errors. It is not a hash: attackers can easily craft collisions. Use only for hardware noise detection, never for security.","mental_model" => "Tiny parity check on steroids.","purpose" => ["error detection", "small payloads", "hardware protocols"],"good_for" => ["sensor data", "I2C/SMBus", "CAN bus", "UART frames"],"avoid_for" => ["security", "large files", "malicious environments"],"pros" => ["very fast", "tiny overhead", "hardware friendly"],"cons" => ["1 byte only", "not secure", "many variants"],"difficulty" => 1, "security" => 1,"quantum_impact" => "Not cryptographic; unaffected.","post_quantum_status" => 1,"example" => ["scenario" => "SMBus temperature sensor packet","input" => ["data" => "\x01\x5a\x00"],"output" => ["crc8" => "0x7e"]],"flow" => ["initialize polynomial", "process each byte", "XOR with table", "final remainder"],"related" => ["crc16", "crc32", "adler32"]],
        ["algo" => 23, "uuid" => "b450c8", "name" => "crc16","type" => "checksum", "status" => "active","title" => "CRC-16","description_md" => "CRC-16 is a 2-byte checksum used in Modbus, USB, and X.25. It detects burst errors up to 16 bits and all odd-bit errors. There are multiple polynomials (CRC-16-IBM, CRC-16-CCITT); ensure sender and receiver agree. It is fast and cheap but not collision-resistant. Use for integrity checking in trusted channels, never for authentication.","mental_model" => "Short fingerprint for wire noise.","purpose" => ["error detection", "medium payloads", "serial protocols"],"good_for" => ["Modbus", "USB", "X.25", "serial comms"],"avoid_for" => ["security", "untrusted data", "large files"],"pros" => ["fast", "2-byte overhead", "hardware support"],"cons" => ["not secure", "polynomial confusion", "collisions possible"],"difficulty" => 1, "security" => 1,"quantum_impact" => "Not cryptographic; unaffected.","post_quantum_status" => 1,"example" => ["scenario" => "Modbus RTU frame","input" => ["frame" => "\x01\x03\x00\x00\x00\x0a"],"output" => ["crc16" => "0xc40f"]],"flow" => ["init 0xFFFF", "XOR with polynomial", "shift and reduce", "invert result"],"related" => ["crc16-ccitt", "crc32", "modbus"]],
        ["algo" => 24, "uuid" => "5952dc", "name" => "crc16-ccitt","type" => "checksum", "status" => "active","title" => "CRC-16-CCITT","description_md" => "CRC-16-CCITT uses polynomial 0x1021 (X.25, V.41, HDLC, Bluetooth). It is the default in many telecom and wireless protocols. It detects all single and double-bit errors and most burst errors. Like all CRCs, it is not a cryptographic hash. Use for Bluetooth packets, PPP frames, and RFID systems where noise is the threat, not attackers.","mental_model" => "Telecom-standard noise detector.","purpose" => ["telecom error detection", "wireless", "HDLC"],"good_for" => ["Bluetooth", "RFID", "PPP", "X.25", "HDLC"],"avoid_for" => ["security", "file integrity", "untrusted networks"],"pros" => ["standardized", "good error coverage", "fast"],"cons" => ["not secure", "polynomial-specific", "2-byte limit"],"difficulty" => 1, "security" => 1,"quantum_impact" => "Not cryptographic; unaffected.","post_quantum_status" => 1,"example" => ["scenario" => "Bluetooth LE packet","input" => ["payload" => "\x02\x01\x06\x03\x03\xaa\xfe"],"output" => ["crc16-ccitt" => "0x6e20"]],"flow" => ["init 0xFFFF or 0x1D0F", "poly 0x1021", "process bytes", "final XOR"],"related" => ["crc16", "crc32", "bluetooth"]],
        ["algo" => 25, "uuid" => "5d1ffd", "name" => "crc32","type" => "checksum", "status" => "active","title" => "CRC-32 (IEEE 802.3)","description_md" => "CRC-32 is the 4-byte checksum in Ethernet, ZIP, PNG, and MPEG-2. It uses polynomial 0x04C11DB7 and detects burst errors up to 32 bits. It is extremely fast with hardware and lookup-table implementations. It is not a hash: two different files can have the same CRC32. Use for accidental corruption detection, never for security or deduplication.","mental_model" => "Ethernet's built-in spell-check.","purpose" => ["error detection", "file integrity", "network frames"],"good_for" => ["ZIP", "PNG", "Ethernet", "MPEG", "file transfers"],"avoid_for" => ["security", "hashing", "untrusted data"],"pros" => ["very fast", "4-byte overhead", "hardware accelerated"],"cons" => ["not secure", "collisions easy", "not a hash"],"difficulty" => 1, "security" => 1,"quantum_impact" => "Not cryptographic; unaffected.","post_quantum_status" => 1,"example" => ["scenario" => "PNG image chunk","input" => ["chunk_data" => "IHDR\x00\x00\x00\x01\x00\x00\x00\x01\x08\x02\x00\x00\x00"],"output" => ["crc32" => "0x2176457c"]],"flow" => ["init 0xFFFFFFFF", "reflect bits", "poly 0xEDB88320", "final invert"],"related" => ["crc32c", "adler32", "zip"]],
        ["algo" => 26, "uuid" => "8d5d50", "name" => "crc32c","type" => "checksum", "status" => "active","title" => "CRC-32C (Castagnoli)","description_md" => "CRC-32C uses polynomial 0x1EDC6F41 and is hardware-accelerated in modern Intel/ARM CPUs (SSE4.2, CRC32 instructions). It is the default in iSCSI, SCTP, and Btrfs/ZFS. It is faster than CRC-32 on modern hardware and has better error detection for short payloads. Still not a hash: do not use for security.","mental_model" => "CRC-32 with a CPU boost.","purpose" => ["hardware-accelerated checksum", "storage", "network"],"good_for" => ["iSCSI", "SCTP", "ZFS", "Btrfs", "KVM"],"avoid_for" => ["security", "hashing", "untrusted data"],"pros" => ["CPU instructions", "better short-packet detection", "fast"],"cons" => ["not secure", "not a hash", "requires modern CPU"],"difficulty" => 1, "security" => 1,"quantum_impact" => "Not cryptographic; unaffected.","post_quantum_status" => 1,"example" => ["scenario" => "iSCSI data integrity","input" => ["scsi_block" => "\x00\x00\x00\x00... (512 bytes)"],"output" => ["crc32c" => "0x8a9136aa"]],"flow" => ["init 0xFFFFFFFF", "poly 0x82F63B78 (reversed)", "hardware or LUT", "final invert"],"related" => ["crc32", "sctp", "iscsi"]],
        ["algo" => 27, "uuid" => "604f18", "name" => "crc64","type" => "checksum", "status" => "active","title" => "CRC-64 (ISO)","description_md" => "CRC-64 uses polynomial 0x000000000000001B and produces an 8-byte checksum. It is used in D-Bus, XZ compression, and file systems needing larger checksums. It catches more errors than CRC-32 but is slower and not collision-resistant. Use when 32 bits feels too small for large data, but still not for security.","mental_model" => "Bigger safety net for large files.","purpose" => ["large file checksum", "compression", "databases"],"good_for" => ["XZ", "D-Bus", "large archives", "file systems"],"avoid_for" => ["security", "small payloads", "speed-critical"],"pros" => ["8-byte coverage", "good for large data", "standardized"],"cons" => ["slower than CRC32", "not secure", "8-byte overhead"],"difficulty" => 1, "security" => 1,"quantum_impact" => "Not cryptographic; unaffected.","post_quantum_status" => 1,"example" => ["scenario" => "XZ archive integrity","input" => ["block" => "\xfd\x37\x7a\x58\x5a\x00... (compressed data)"],"output" => ["crc64" => "0x995dc9bfdf193a7a"]],"flow" => ["init 0xFFFFFFFFFFFFFFFF", "poly 0x42F0E1EBA9EA3693", "process bytes", "final XOR"],"related" => ["crc64-ecma", "crc32", "xz"]],
        ["algo" => 28, "uuid" => "579bf2", "name" => "crc64-ecma","type" => "checksum", "status" => "active","title" => "CRC-64-ECMA","description_md" => "CRC-64-ECMA uses polynomial 0x42F0E1EBA9EA3693 and is the standard in ECMA-182. It is used in Go's hash/crc64 package and some database systems. Like all CRCs, it is for error detection, not security. It provides a larger checksum space than CRC-32, reducing collision probability for accidental errors.","mental_model" => "Database-friendly big checksum.","purpose" => ["large data integrity", "databases", "Go programs"],"good_for" => ["Go hash/crc64", "database pages", "large objects", "logs"],"avoid_for" => ["security", "small data", "speed-critical"],"pros" => ["8-byte coverage", "Go standard", "good for pages"],"cons" => ["slower", "not secure", "rare outside Go"],"difficulty" => 1, "security" => 1,"quantum_impact" => "Not cryptographic; unaffected.","post_quantum_status" => 1,"example" => ["scenario" => "Go database page checksum","input" => ["page" => "\x01\x00\x00\x00... (4096 bytes)"],"output" => ["crc64-ecma" => "0x6c40df5f0b497347"]],"flow" => ["init 0xFFFFFFFFFFFFFFFF", "poly ECMA-182", "table-driven", "final XOR"],"related" => ["crc64", "go", "database"]],
        ["algo" => 29, "uuid" => "6f8bde", "name" => "adler32","type" => "checksum", "status" => "active","title" => "Adler-32","description_md" => "Adler-32 is a fast checksum used in zlib and PNG. It is faster than CRC-32 but weaker for short messages (fewer than a few hundred bytes). It combines two 16-bit sums modulo prime numbers. Use for compression streams and large files where speed matters more than strong error detection. Not for security.","mental_model" => "Quick-and-dirty integrity for compressed data.","purpose" => ["fast checksum", "compression", "large streams"],"good_for" => ["zlib", "PNG", "gzip", "large file transfer"],"avoid_for" => ["short messages", "security", "untrusted data"],"pros" => ["very fast", "simple", "good for large data"],"cons" => ["weak for short data", "not secure", "collisions likely"],"difficulty" => 1, "security" => 1,"quantum_impact" => "Not cryptographic; unaffected.","post_quantum_status" => 1,"example" => ["scenario" => "zlib compressed stream","input" => ["data" => "The quick brown fox jumps over the lazy dog"],"output" => ["adler32" => "0x5bdc0fda"]],"flow" => ["A = 1, B = 0", "A = (A + byte) mod 65521", "B = (B + A) mod 65521", "B << 16 | A"],"related" => ["crc32", "zlib", "gzip"]],
        ["algo" => 30, "uuid" => "c76897", "name" => "fletcher16","type" => "checksum", "status" => "active","title" => "Fletcher-16","description_md" => "Fletcher-16 is a simple checksum using two 8-bit accumulators. It is weaker than CRC but faster on 8-bit microcontrollers. Used in legacy embedded systems and some network protocols. It detects most single-bit errors but is not suitable for security or high-integrity applications. Prefer CRC or cryptographic hashes for anything critical.","mental_model" => "Tiny checksum for tiny computers.","purpose" => ["embedded checksum", "8-bit systems", "legacy protocols"],"good_for" => ["microcontrollers", "UART", "legacy embedded", "ZFS boot"],"avoid_for" => ["security", "large files", "modern systems"],"pros" => ["very simple", "fast on 8-bit", "small code"],"cons" => ["weak detection", "8-bit limit", "obsolete"],"difficulty" => 1, "security" => 1,"quantum_impact" => "Not cryptographic; unaffected.","post_quantum_status" => 1,"example" => ["scenario" => "8-bit sensor packet","input" => ["data" => "\x01\x02\x03\x04"],"output" => ["fletcher16" => "0x040a"]],"flow" => ["sum1 = 0, sum2 = 0", "sum1 = (sum1 + byte) mod 255", "sum2 = (sum2 + sum1) mod 255", "sum2 << 8 | sum1"],"related" => ["fletcher32", "crc8", "adler32"]],
        ["algo" => 31, "uuid" => "22f95e", "name" => "fletcher32","type" => "checksum", "status" => "active","title" => "Fletcher-32","description_md" => "Fletcher-32 extends Fletcher-16 to 16-bit accumulators, giving a 32-bit checksum. It is faster than CRC-32 on 16-bit processors and used in some file systems (ZFS). It detects more errors than Fletcher-16 but still falls short of CRC-32 for random error patterns. Use for speed on constrained hardware, not for security.","mental_model" => "Fletcher-16 grown to 32 bits.","purpose" => ["medium checksum", "16-bit systems", "file systems"],"good_for" => ["ZFS", "embedded", "16-bit CPUs", "boot loaders"],"avoid_for" => ["security", "untrusted data", "internet protocols"],"pros" => ["fast on 16-bit", "better than Fletcher16", "simple"],"cons" => ["weaker than CRC32", "not secure", "modulo 65535"],"difficulty" => 1, "security" => 1,"quantum_impact" => "Not cryptographic; unaffected.","post_quantum_status" => 1,"example" => ["scenario" => "ZFS block checksum","input" => ["block" => "\x00\x01\x02\x03... (128 bytes)"],"output" => ["fletcher32" => "0x5d6c2b8a"]],"flow" => ["sum1 = 0, sum2 = 0", "sum1 = (sum1 + byte) mod 65535", "sum2 = (sum2 + sum1) mod 65535", "sum2 << 16 | sum1"],"related" => ["fletcher16", "crc32", "adler32"]],
        ["algo" => 32, "uuid" => "2ba5ea", "name" => "xxhash32","type" => "checksum", "status" => "active","title" => "xxHash-32","description_md" => "xxHash-32 is a non-cryptographic hash designed for speed. It processes data at RAM speed limits and is used in hash tables, checksums, and deduplication. It is not secure: attackers can generate collisions. Use for performance-critical applications where security is not needed. It is faster than MD5 and CRC32 on modern CPUs.","mental_model" => "Speed demon for hash tables.","purpose" => ["fast hashing", "hash tables", "deduplication", "checksums"],"good_for" => ["hash maps", "file dedup", "game assets", "caches"],"avoid_for" => ["security", "passwords", "signatures", "untrusted data"],"pros" => ["RAM-speed", "simple API", "portable"],"cons" => ["not secure", "collisions possible", "32-bit limit"],"difficulty" => 1, "security" => 1,"quantum_impact" => "Not cryptographic; unaffected.","post_quantum_status" => 1,"example" => ["scenario" => "Hash table key for game asset","input" => ["filename" => "textures/hero_diffuse.png"],"output" => ["xxhash32" => "0x9e5f42b1"]],"flow" => ["seeded accumulator", "striped processing", "avalanche mixing", "finalize"],"related" => ["xxhash64", "xxh3", "murmur3"]],
        ["algo" => 33, "uuid" => "5c738d", "name" => "xxhash64","type" => "checksum", "status" => "active","title" => "xxHash-64","description_md" => "xxHash-64 is the 64-bit variant of xxHash, providing a larger hash space with similar speed. It is the default in databases, file systems, and big data pipelines. It is not secure but has excellent collision resistance for non-malicious data. Use for Bloom filters, file indexing, and any high-performance hashing need.","mental_model" => "xxHash with a bigger bucket.","purpose" => ["fast 64-bit hash", "databases", "big data", "indexing"],"good_for" => ["Bloom filters", "file systems", "data pipelines", "caches"],"avoid_for" => ["security", "passwords", "MACs", "untrusted input"],"pros" => ["64-bit space", "RAM-speed", "excellent distribution"],"cons" => ["not secure", "not a MAC", "seed-dependent"],"difficulty" => 1, "security" => 1,"quantum_impact" => "Not cryptographic; unaffected.","post_quantum_status" => 1,"example" => ["scenario" => "Database shard key","input" => ["user_id" => "user_12345@example.com"],"output" => ["xxhash64" => "0x7f8e9d2a3b4c5d6e"]],"flow" => ["64-bit seed", "striped 32-bit lanes", "merge accumulators", "avalanche"],"related" => ["xxhash32", "xxh3", "cityhash"]],
        ["algo" => 34, "uuid" => "a8e3de", "name" => "xxh3","type" => "checksum", "status" => "active","title" => "XXH3","description_md" => "XXH3 is the latest xxHash generation, faster than XXH64 on short inputs and supporting 128-bit outputs. It uses a new algorithm with better collision resistance and is the recommended choice for new projects. It is still not a cryptographic hash. Use for high-performance deduplication, checksumming, and hashing in modern applications.","mental_model" => "The fastest non-crypto hash you should use today.","purpose" => ["ultra-fast hashing", "modern checksums", "short inputs"],"good_for" => ["modern databases", "real-time systems", "network packets", "caches"],"avoid_for" => ["security", "passwords", "signatures", "HMAC replacement"],"pros" => ["fastest xxHash", "128-bit option", "great short-input speed"],"cons" => ["not secure", "newer (less tested)", "not a MAC"],"difficulty" => 1, "security" => 1,"quantum_impact" => "Not cryptographic; unaffected.","post_quantum_status" => 1,"example" => ["scenario" => "Real-time packet deduplication","input" => ["packet" => "\x45\x00\x00\x3c\x1c\x46... (IP header)"],"output" => ["xxh3" => "0x8a3d7b2f1e9c4d5a"]],"flow" => ["secret seed", "accumulator rounds", "striped lanes", "finalize with avalanche"],"related" => ["xxhash64", "xxhash32", "cityhash"]],
    ],
    "legacy" => [
        ["algo" => 10, "uuid" => "ef5073", "name" => "base91","type" => "encoding", "status" => "legacy","title" => "Base91","description_md" => "Base91 encodes binary into 91 printable ASCII characters, achieving ~23% overhead. It was designed for embedding binary in email and Usenet posts. It is not standardized and has limited library support. Base85 or Base64 are better choices today. Use only when maintaining legacy systems that already use Base91.","mental_model" => "Overly clever email encoding from the 90s.","purpose" => ["legacy binary-to-text", "email embedding", "Usenet"],"good_for" => ["legacy systems", "retro projects", "minimal overhead"],"avoid_for" => ["new projects", "URLs", "standardized APIs"],"pros" => ["low overhead", "printable ASCII"],"cons" => ["not standardized", "rare libraries", "complex encoding"],"difficulty" => 2, "security" => 1,"quantum_impact" => "Not a cryptographic primitive; unaffected.","post_quantum_status" => 5,"example" => ["scenario" => "Legacy email attachment encoding","input" => ["binary" => "Hello"],"output" => ["base91" => "xKJB2"]],"flow" => ["treat as big integer", "divide by 91", "map to 91 chars"],"related" => ["base85", "base64", "uuencode"]],
        ["algo" => 15, "uuid" => "9570c8", "name" => "ber","type" => "format", "status" => "legacy","title" => "BER (Basic Encoding Rules)","description_md" => "BER is the original ASN.1 encoding, more flexible than DER but non-canonical. Multiple valid BER encodings can exist for the same data, which breaks digital signatures. It was common in SNMP and early PKI. Modern systems use DER or CER for signatures. Use BER only when interfacing with legacy SNMP agents or old mainframe systems.","mental_model" => "DER's loose predecessor.","purpose" => ["legacy ASN.1", "SNMP", "old PKI"],"good_for" => ["SNMP", "legacy mainframes", "old certificates", "historical systems"],"avoid_for" => ["signatures", "new PKI", "TLS", "modern APIs"],"pros" => ["flexible", "legacy support", "SNMP compatible"],"cons" => ["not canonical", "breaks signatures", "obsolete"],"difficulty" => 3, "security" => 1,"quantum_impact" => "Container format; quantum impact depends on enclosed algorithm.","post_quantum_status" => 3,"example" => ["scenario" => "SNMPv1 packet","input" => ["oid" => "1.3.6.1.2.1.1.1.0", "value" => "RouterOS"],"output" => ["ber" => "302602010004067075626c6963a4190204..."]],"flow" => ["encode ASN.1", "allow indefinite length", "optional canonicalization"],"related" => ["der", "cer", "snmp"]],
    ]
];
?>